SELECT COUNT(*) AS num_discharges
FROM personnel
WHERE date_of_discharge BETWEEN '1870-01-01' AND '1879-12-31';

SELECT p.name, r.rank_name
FROM personnel p
LEFT JOIN ranks r ON p.rank_id = r.rank_id;

SELECT personnel.name, personnel.service_branch, ranks.rank_name
FROM personnel
INNER JOIN ranks ON personnel.rank_id = ranks.rank_id;

SELECT rank_name
FROM ranks
WHERE rank_id > 5;

SELECT personnel.name, occupations.occupation_name
FROM personnel
INNER JOIN occupations ON personnel.occupation_id = occupations.occupation_id;

SELECT FLOOR(AVG(age)) AS rounded_down_average_age
FROM personnel
WHERE rank_id < 5 AND service_branch = 'Army';

SELECT name 
FROM personnel 
WHERE personnel_id = 0;

SELECT service_branch, ROUND(AVG(age)) AS average_age
FROM personnel
GROUP BY service_branch;
